                  <h1 style="font-size: 24px; line-height: 30px; margin-top: 25px; margin-bottom: 0; text-align: left; font-weight: 400; padding: 0 10px 10px 20px; margin: 0;">En kreditupplysning har tagits på dig via UC</h1>\r\n                        </div>\r\n                      </td>\r\n                    </tr>\r\n                    <tr>\r\n                      <td align="left" style="font-size: 0px; padding-top: 0; padding-right: 0; padding-bottom: 20px; padding-left: 0; word-break: break-word; padding: 0;">\r\n                        <div style="font-family:Helvetica, Arial, sans-serif;font-size:16px;font-weight:400;line-height:24px;text-align:left;color:#22201C;">\r\n                          <p style="margin: 0; font-size: 19px; font-weight: 400; padding: 0 10px 25px 20px;">Logga in på Kivra i appen eller på webben.</p>\r\n                        </div>\r\n                      </td>\r\n                    </tr>\r\n                  </tbody>\r\n                </table>\r\n              </div>\r\n              <!--[if mso | IE]></td></tr></table><![endif]-->\r\n            </td>\r\n          </tr>\r\n        </tbody>\r\n      </table>\r\n    </div>\r\n    <!--[if mso | IE]></td></tr></table><![endif]-->\r\n    <!--  --><!--  -->\r\n    <!--[if mso | IE]><table align="center" border="0" cellpadding="0" cellspacing="0" class="faq-outlook" role="presentation" style="width:600px;" width="600" ><tr><td style="line-height:0px;font-size:0px;mso-line-height-rule:exactly;"><![endif]-->\r\n    <div class="faq" style="border: 1px solid #EEEBE8; border-radius: 8px; margin: 0px auto; max-width: 600px; margin-top: 32px;">\r\n      <table align="center" border="0" cellpadding="0" cellspacing="0" role="presentation" style="width:100%;">\r\n        <tbody>\r\n          <tr>\r\n            <td style="direction: ltr; font-size: 0px; text-align: center; padding: 0;" align="center">\r\n              <!--[if mso | IE]><table role="presentation" border="0" cellpadding="0" cellspacing="0"><tr><td class="" style="vertical-align:top;width:600px;" ><![endif]-->\r\n              <div class="mj-column-per-100 mj-outlook-group-fix" style="font-size:0px;text-align:left;direction:ltr;display:inline-block;vertical-align:top;width:100%;">\r\n                <table border="0" cellpadding="0" cellspacing="0" role="presentation" style="vertical-align:top;" width="100%">\r\n                  <tbody>\r\n                    <tr>\r\n                      <td align="left" class="headline" style="opacity: 0.65; font-size: 0px; padding-top: 0; padding-right: 0; padding-bottom: 20px; padding-left: 0; word-break: break-word; padding: 20px 20px 0px 20px;">\r\n                        <div style="font-family:Helvetica, Arial, sans-serif;font-size:19px;font-weight:700;line-height:24px;text-align:left;color:#22201C;">Frågor</div>\r\n                      </td>\r\n                    </tr>\r\n                    <tr>\r\n                      <td style="font-size: 0px; word-break: break-word; padding: 0;">\r\n                        <div style="height:15px;line-height:15px;">&#8202;</div>\r\n                      </td>\r\n                    </tr>\r\n                    <!--  -->\r\n                    <tr>\r\n                      <td align="left" class="question" style="opacity: 0.65; font-size: 0px; padding-top: 0; padding-right: 0; padding-bottom: 20px; padding-left: 0; word-break: break-word; padding: 0 20px;">\r\n                        <div style="font-family:Helvetica, Arial, sans-serif;font-size:15px;font-weight:700;line-height:24px;text-align:left;color:#22201C;">Vad är en kreditupplysning?</div>\r\n                      </td>\r\n                    </tr>\r\n                    <tr>\r\n                      <td style="font-size: 0px; word-break: break-word; padding: 0;">\r\n                        <div style="height:6px;line-height:6px;">&#8202;</div>\r\n                      </td>\r\n                    </tr>\r\n                    <tr>\r\n                      <td align="left" class="answer" style="opacity: 0.65; font-size: 0px; padding-top: 0; padding-right: 0; padding-bottom: 20px; padding-left: 0; word-break: break-word; padding: 0 20px;">\r\n                        <div style="font-family:Helvetica, Arial, sans-serif;font-size:15px;font-weight:400;line-height:22px;text-align:left;color:#22201C;">En kreditupplysning är en bedömning av en person som eventuellt ska låna pengar eller bli beviljad en kredit. Företaget som lånar ut pengar eller ger krediter behöver ett underlag för att kunna bedöma om krediten kan beviljas. Personen som söker krediten måste enligt svensk lag informeras om att en kreditupplysning är utförd.</div>\r\n                      </td>\r\n                    </tr>\r\n                    <!--  -->\r\n                    <tr>\r\n                      <td align="left" class="divider" style="font-size: 0px; word-break: break-word; padding: 15px 20px;">\r\n                        <table cellpadding="0" cellspacing="0" width="100%" border="0" style="color:#22201C;font-family:Helvetica, Arial, sans-serif;font-size:16px;line-height:24px;table-layout:auto;width:100%;border:none;">\r\n                          <tr>\r\n                            <td style="border-top: 1.5px solid #EEEBE8; padding: 0;"></td>\r\n                          </tr>\r\n                        </table>\r\n                      </td>\r\n                    </tr>\r\n                    <!--  --><!--  -->\r\n                    <tr>\r\n                      <td align="left" class="question" style="opacity: 0.65; font-size: 0px; padding-top: 0; padding-right: 0; padding-bottom: 20px; padding-left: 0; word-break: break-word; padding: 0 20px;">\r\n                        <div style="font-family:Helvetica, Arial, sans-serif;font-size:15px;font-weight:700;line-height:24px;text-align:left;color:#22201C;">Vem har tagit kreditupplysning?</div>\r\n                      </td>\r\n                    </tr>\r\n                    <tr>\r\n                      <td style="font-size: 0px; word-break: break-word; padding: 0;">\r\n                        <div style="height:6px;line-height:6px;">&#8202;</div>\r\n                      </td>\r\n                    </tr>\r\n                    <tr>\r\n                      <td align="left" class="answer" style="opacity: 0.65; font-size: 0px; padding-top: 0; padding-right: 0; padding-bottom: 20px; padding-left: 0; word-break: break-word; padding: 0 20px;">\r\n                        <div style="font-family:Helvetica, Arial, sans-serif;font-size:15px;font-weight:400;line-height:22px;text-align:left;color:#22201C;">Kivra kan inte se vilket företag som är frågeställare. Det kan du se i själva kreditupplysningen när du mottagit den, i Kivra eller på papper. Själva upplysningen hanteras av något av kreditupplysningsbolagen som finns i Sverige. De vanligaste är:<ul style="margin: 0; padding-left: 20px;"><li>UC</li><li>Creditsafe</li><li>Dun & Bradstreet (formerly Bisnode)</li></ul>För att få mer information om själva upplysningen behöver du vända dig till kreditupplysningsbolaget eller frågeställaren.</div>\r\n                      </td>\r\n                    </tr>\r\n                    <!--  --><!--  -->\r\n                    <tr>\r\n                      <td style="font-size: 0px; word-break: break-word; padding: 0;">\r\n                        <div style="height:20px;line-height:20px;">&#8202;</div>\r\n                      </td>\r\n                    </tr>\r\n                  </tbody>\r\n                </table>\r\n              </div>\r\n              <!--[if mso | IE]></td></tr></table><![endif]-->\r\n            </td>\r\n          </tr>\r\n        </tbody>\r\n      </table>\r\n    </div>\r\n    <!--[if mso | IE]></td></tr></table><![endif]-->\r\n    <!--  -->\r\n    <!--[if mso | IE]><table align="center" border="0" cellpadding="0" cellspacing="0" class="cant-answer-text-outlook" role="presentation" style="width:600px;" width="600" ><tr><td style="line-height:0px;font-size:0px;mso-line-height-rule:exactly;"><![endif]-->\r\n    <div class="cant-answer-text" style="opacity: 0.65; margin: 0px auto; margin-top: 32px; max-width: 250px;">\r\n      <table align="center" border="0" cellpadding="0" cellspacing="0" role="presentation" style="width:100%;">\r\n        <tbody>\r\n          <tr>\r\n            <td style="direction: ltr; font-size: 0px; text-align: center; padding: 0;" align="center">\r\n              <!--[if mso | IE]><table role="presentation" border="0" cellpadding="0" cellspacing="0"><tr><td class="" style="vertical-align:top;width:600px;" ><![endif]-->\r\n              <div class="mj-column-per-100 mj-outlook-group-fix" style="font-size:0px;text-align:left;direction:ltr;display:inline-block;vertical-align:top;width:100%;">\r\n                <table border="0" cellpadding="0" cellspacing="0" role="presentation" style="vertical-align:top;" width="100%">\r\n                  <tbody>\r\n                    <tr>\r\n                      <td align="center" style="font-size: 0px; padding-top: 0; padding-right: 0; padding-bottom: 20px; padding-left: 0; word-break: break-word; padding: 0;">\r\n                        <div style="font-family:Helvetica, Arial, sans-serif;font-size:15px;font-weight:400;line-height:22px;text-align:center;color:#22201C;">Det här mailet skickades automatiskt och går inte att svara på.</div>\r\n                      </td>\r\n                    </tr>\r\n                  </tbody>\r\n                </table>\r\n              </div>\r\n              <!--[if mso | IE]></td></tr></table><![endif]-->\r\n            </td>\r\n          </tr>\r\n        </tbody>\r\n      </table>\r\n    </div>\r\n    <!--[if mso | IE]></td></tr></table><table align="center" border="0" cellpadding="0" cellspacing="0" class="kivra-info-outlook" role="presentation" style="width:600px;" width="600" ><tr><td style="line-height:0px;font-size:0px;mso-line-height-rule:exactly;"><![endif]-->\r\n    <div class="kivra-info" style="