idth:550px;" ><![endif]-->\r\n            \r\n      <div class="mj-column-per-100 mj-outlook-group-fix" style="font-size:0px;text-align:left;direction:ltr;display:inline-block;vertical-align:top;width:100%;">\r\n        \r\n      <table border="0" cellpadding="0" cellspacing="0" role="presentation" style="vertical-align:top;" width="100%">\r\n        <tbody>\r\n          \r\n              <tr>\r\n                <td style="font-size:0px;word-break:break-word;">\r\n                  \r\n      <div style="height:20px;line-height:20px;">&#8202;</div>\r\n    \r\n                </td>\r\n              </tr>\r\n            \r\n              <tr>\r\n                <td align="left" style="font-size:0px;padding:10px 25px;padding-top:3px;padding-right:5px;padding-bottom:3px;padding-left:5px;word-break:break-word;">\r\n                  \r\n      <div style="font-family:Arial;font-size:16px;font-weight:400;line-height:150%;text-align:left;color:#333333;"><div><div><div><div><div><div><div><div>Hello Apidog Users,</div><div>&nbsp;</div><div><div>October has been a month of refinement and powerful new capabilities! We've focused on enhancing your testing workflow, improving documentation customization, and adding smarter controls across the platform. Here's everything new in Apidog this month:</div></div></div></div></div></div></div></div></div></div>\r\n    \r\n                </td>\r\n              </tr>\r\n            \r\n              <tr>\r\n                <td align="left" style="font-size:0px;padding:10px 25px;padding-top:3px;padding-right:5px;padding-bottom:3px;padding-left:5px;word-break:break-word;">\r\n                  \r\n      <div style="font-family:Arial;font-size:16px;font-weight:400;line-height:150%;text-align:left;color:#333333;"><div>&nbsp;</div></div>\r\n    \r\n                </td>\r\n              </tr>\r\n            \r\n              <tr>\r\n                <td align="center" style="font-size:0px;padding:10px 25px;padding-top:3px;padding-right:5px;padding-bottom:3px;padding-left:5px;word-break:break-word;">\r\n                  \r\n      <div style="font-family:Arial;font-size:16px;font-weight:400;line-height:150%;text-align:center;color:#333333;"><div><span style="background-color:#ffffff;font-size:24px"><strong>⭐ New Updates</strong></span></div></div>\r\n    \r\n                </td>\r\n              </tr>\r\n            \r\n              <tr>\r\n                <td align="left" style="font-size:0px;padding:10px 25px;padding-top:3px;padding-right:5px;padding-bottom:3px;padding-left:5px;word-break:break-word;">\r\n                  \r\n      <div style="font-family:Arial;font-size:16px;font-weight:400;line-height:150%;text-align:left;color:#333333;"><div>🔥&nbsp;<span><strong>Real-Time Preview for Published Documentation Customization:</strong></span> Take the guesswork out of documentation styling! When configuring the&nbsp;<span style="background-color:#e5e6eb">Customize</span> settings for your published documentation, you can now see changes in real-time. Perfect your branding and layout with instant visual feedback before publishing.<span style="color:#1967ff"><a href="https://jff6wzsr.r.us-east-1.awstrack.me/L0/https:%2F%2Fapidog.canny.io%2Fchangelog/1/0100019a2b495a49-82e95d20-5c5a-42c8-9498-e67d45bcf3fe-000000/GbAF_1kBw2WzLBK2AD8AlNAoaMs=450" target="_blank"></a></span><span style="color:#1967ff"><a href="https://jff6wzsr.r.us-east-1.awstrack.me/L0/https:%2F%2Fapidog.canny.io%2Fchangelog/2/0100019a2b495a49-82e95d20-5c5a-42c8-9498-e67d45bcf3fe-000000/A_7yRjNNvpwejri4pp5RcZ-tWwM=450" target="_blank"></a></span><span style="color:#1967ff"><a href="https://jff6wzsr.r.us-east-1.awstrack.me/L0/https:%2F%2Fapidog.canny.io%2Fchangelog/3/0100019a2b495a49-82e95d20-5c5a-42c8-9498-e67d45bcf3fe-000000/L84pC1Do-udZnTVUiA_oYs1oCuI=450" target="_blank"></a></span><span style="color:#1967ff"></span><span style="color:#1967ff"><a href="https://jff6wzsr.r.us-east-1.awstrack.me/L0/https:%2F%2Fapidog.canny.io%2Fchangelog/4/0100019a2b495a49-82e95d20-5c5a-42c8-9498-e67d45bcf3fe-000000/-hLH61-mE9ZU4U4INnBWP1F7jBE=450" target="_blank"></a></span><span style="color:#1967ff"></span><span style="color:#1967ff"><a href="https://jff6wzsr.r.us-east-1.awstrack.me/L0/https:%2F%2Fapidog.canny.io%2Fchangelog/5/0100019a2b495a49-82e95d20-5c5a-42c8-9498-e67d45bcf3fe-000000/LOHEQkasEdVnMuZfsHFzFFQI7cU=450" target="_blank"></a></span><span style="color:#1967ff"></span><span style="color:#1967ff"><a href="https://jff6wzsr.r.us-east-1.awstrack.me/L0/https:%2F%2Fapidog.canny.io%2Fchangelog/6/0100019a2b495a49-82e95d20-5c5a-42c8-9498-e67d45bcf3fe-000000/M5Zg5UCIY59BrnRdhf2JrSwUYfg=450" target="_blank"></a></span><span style="color:#1967ff"></span><span style="color:#1967ff"></span><span style="color:#1967ff"></span><span style="color:#1967ff"><a href="https://jff6wzsr.r.us-east-1.awstrack.me/L0/https:%2F%2Fapidog.canny.io%2Fchangelog/7/0100019a2b495a49-82e95d20-5c5a-42c8-9498-e67d45bcf3fe-000000/IcjehMA7KS6ORbhd5iUjYFjt7Dk=450" target="_blank"></a></span><span style="color:#1967ff"><a href="https://jff6wzsr.r.us-east-1.awstrack.me/L0/https:%2F%2Fapidog.canny.io%2Fchangelog/8/0100019a2b495a49-82e95d20-5c5a-42c8-9498-e67d45bcf3fe-000000/VN1NN5CTzR9cfc74u_btb7efkgY=450" target="_blank"></a></span><span style="color:#1967ff"><a href="https://jff6wzsr.r.us-east-1.awstrack.me/L0/https:%2F%2Fapidog.canny.io%2Fchangelog/9/0100019a2b495a49-82e95d20-5c5a-42c8-9498-e67d45bcf3fe-000000/QqsivM2Me5iBti5QAFQNR5axA1Q=450" target="_blank"></a></span><span style="color:#1967ff"><a href="https://jff6wzsr.r.us-east-1.awstrack.me/L0/https:%2F%2Fapidog.canny.io%2Fchangelog/10/0100019a2b495a49-82e95d20-5c5a-42c8-9498-e67d45bcf3fe-000000/DDadpzTfSQYHdIm42jNTfTk-FuU=450" target="_blank"></a></span><span style="color:#1967ff"></span><span style="color:#1967ff"><a href="https://jff6wzsr.r.us-east-1.awstrack.me/L0/https:%2F%2Fapidog.canny.io%2Fchangelog/11/0100019a2b495a49-82e95d20-5c5a-42c8-9498-e67d45bcf3fe-000000/xGNKxh4LwReD1aqALVrP7o1EArA=450" target="_blank"></a></span><span style="color:#1967ff"></span><span style="color:#1967ff"><a href="https://jff6wzsr.r.us-east-1.awstrack.me/L0/https:%2F%2Fapidog.canny.io%2Fchangelog/12/0100019a2b495a49-82e95d20-5c5a-42c8-9498-e67d45bcf3fe-000000/8TTF0MdmGOp_2p5Pv3rSVCMfksM=450" target="_blank"></a></span><span style="color:#1967ff"></span><span style="color:#1967ff"><a href="https://jff6wzsr.r.us-east-1.awstrack.me/L0/https:%2F%2Fapidog.canny.io%2Fchangelog/13/0100019a2b495a49-82e95d20-5c5a-42c8-9498-e67d45bcf3fe-000000/9QsGpzqO-unSa2tStrO6dy3cNnM=450" target="_blank"></a></span><span style="color:#1967ff"></span><span style="color:#1967ff"></span><span style="color:#1967ff"></span><span style="color:#1967ff"><a href="https://jff6wzsr.r.us-east-1.awstrack.me/L0/https:%2F%2Fapidog.canny.io%2Fchangelog/14/0100019a2b495a49-82e95d20-5c5a-42c8-9498-e67d45bcf3fe-000000/s0abMAbFKAkWKAn1_ij-ihd0CD8=450" target="_blank"></a></span></div></div>\r\n    \r\n                </td>\r\n              </tr>\r\n            \r\n              <tr>\r\n                <td align="center" style="font-size:0px;padding:10px 25px;padding-right:5px;padding-left:5px;word-break:break-word;">\r\n                  \r\n      <table border="0" cellpadding="0" cellspacing="0" role="presentation" style="border-collapse:collapse;border-spacing:0px;">\r\n        <tbody>\r\n          <tr>\r\n            <td style="width:540px;">\r\n              \r\n        <a href="https://jff6wzsr.r.us-east-1.awstrack.me/L0/https:%2F%2Fassets.apidog.com%2Fuploads%2Fhelp%2F2025%2F10%2F27%2Fo5x6b-6s.gif/1/0100019a2b495a49-82e95d20-5c5a-42c8-9498-e67d45bcf3fe-000000/-tBCzOLMS7v0zDDiuSmw69qGEUI=450" target="_blank">\r\n          \r\n      <img src="https://assets.apidog.com/uploads/help/2025/10/27/o5x6b-6s.gif" style="border:0;display:block;outline:none;text-decoration:none;height:auto;width:100%;font-size:13px;" width="540" height="auto">\r\n    \r\n        </a>\r\n      \r\n            </td>\r\n          </tr>\r\n        </tbody>\r\n      </table>\r\n    \r\n                </td>\r\n              </tr>\r\n            \r\n              <tr>\r\n                <td align="left" style="font-size:0px;padding:10px 25px;padding-top:3px;padding-right:5px;padding-bottom:3px;padding-left:5px;word-break:break-word;">\r\n                  \r\n      <div style="font-family:Arial;font-size:16px;font-style:normal;font-weight:400;line-height:150%;text-align:left;color:#333333;"><div><div>🎨&nbsp;<span><strong>Smarter API Design Controls:</strong></span>&nbsp;</div><ul><li>Set whether request bodies are required when designing APIs for clearer specifications</li><li>When selecting status code 204 while designing an endpoint, the content type automatically switches to&nbsp;<span style="background-color:#e5e6eb">No-Content</span> for proper REST compliance.</li></ul></div></div>\r\n    \r\n                </td>\r\n              </tr>\r\n            \r\n              <tr>\r\n                <td align="left" style="font-size:0px;padding:10px 25px;padding-top:3px;padding-right:5px;padding-bottom:3px;padding-left:5px;word-break:break-word;">\r\n                  \r\n      <div style="font-family:Arial;font-size:16px;font-style:normal;font-weight:400;line-height:150%;text-align:left;color:#333333;"><div>🌐&nbsp;<span><strong>Improved SSE Debugging for Endpoints Related to&nbsp;</strong></span><span style="background-color:#e5e6eb"><strong>AI with LLMs</strong></span><span><strong>:</strong></span> When debugging SSE streaming responses for endpoints related to&nbsp;<span style="background-color:#e5e6eb">AI with LLM</span> using the Cloud Agent in the web version, the timeline content now displays correctly, ensuring smooth real-time debugging experiences.</div></div>\r\n    \r\n                </td>\r\n              </tr>\r\n            \r\n              <tr>\r\n                <td align="left" style="font-size:0px;padding:10px 25px;padding-top:3px;padding-right:5px;padding-bottom:3px;padding-left:5px;word-break:break-word;">\r\n                  \r\n      <div style="font-family:Arial;font-size:16px;font-weight:400;line-height:150%;text-align:left;color:#333333;">🏷️&nbsp;<span><strong>Advanced Test Case Management with Tags:</strong></span> You can now add tags to test cases and manage both tags and categories, making it easier to organize, filter, and maintain a large number of test cases. Find exactly what you need, when you need it.&nbsp;</div>\r\n    \r\n                </td>\r\n              </tr>\r\n            \r\n              <tr>\r\n                <td align="left" style="background:#FFFFFF;font-size:0px;padding:10px 25px;padding-top:3px;padding-right:5px;padding-bottom:3px;padding-left:5px;word-break:break-word;">\r\n                  \r\n      <div style="font-family:Arial;font-size:16px;font-weight:400;line-height:150%;text-align:left;color:#333333;">⚖️&nbsp;<span><strong>HTTP Status Code Assertions:</strong></span> Testing validation gets more precise with support for assertions based on HTTP status codes. Create more robust test scenarios that validate not just response content, but also proper status codes.</div>\r\n    \r\n                </td>\r\n              </tr>\r\n            \r\n              <tr>\r\n                <td align="left" style="font-size:0px;padding:10px 25px;padding-top:3px;padding-right:5px;padding-bottom:3px;padding-left:5px;word-break:break-word;">\r\n                  \r\n      <div style="font-family:Arial;font-size:16px;font-weight:400;line-height:150%;text-align:left;color:#333333;">📊&nbsp;<span><strong>Bulk Test Scenario Modifications:</strong></span> Efficiency meets scale! Test scenarios now support bulk editing, allowing you to modify multiple scenarios simultaneously.&nbsp;</div>\r\n    \r\n                </td>\r\n              </tr>\r\n            \r\n              <tr>\r\n                <td align="left" style="font-size:0px;padding:10px 25px;padding-top:3px;padding-right:5px;padding-bottom:3px;padding-left:5px;word-break:break-word;">\r\n                  \r\n      <div style="font-family:Arial;font-size:16px;font-weight:400;line-height:150%;text-align:left;color:#333333;">🔐&nbsp;<span><strong>Enhanced Branch Protection Controls:</strong></span> You can now configure whether branch admins are allowed to directly modify protected branch content, giving you granular control over your development workflow and code quality processes.</div>\r\n    \r\n                </td>\r\n              </tr>\r\n            \r\n              <tr>\r\n                <td align="center" style="font-size:0px;padding:10px 25px;padding-right:5px;padding-left:5px;word-break:break-word;">\r\n                  \r\n      <table border="0" cellpadding="0" cellspacing="0" role="presentation" style="border-collapse:collapse;border-spacing:0px;">\r\n        <tbody>\r\n          <tr>\r\n            <td style="width:540px;">\r\n              \r\n        <a href="https://jff6wzsr.r.us-east-1.awstrack.me/L0/https:%2F%2Fassets.apidog.com%2Fuploads%2Fhelp%2F2025%2F10%2F27%2Fo5x6b-6s.gif/2/0100019a2b495a49-82e95d20-5c5a-42c8-9498-e67d45bcf3fe-000000/pnF2pGUGAbJrDot_VERa0HJC71Q=450" target="_blank">\r\n          \r\n      <img src="https://assets.apidog.com/uploads/help/2025/10/27/o5x6b-6s.gif" style="border:0;display:block;outline:none;text-decoration:none;height:auto;width:100%;font-size:13px;" width="540" height="auto">\r\n    \r\n        </a>\r\n      \r\n            </td>\r\n          </tr>\r\n        </tbody>\r\n      </table>\r\n    \r\n                </td>\r\n              </tr>\r\n            \r\n              <tr>\r\n                <td align="left" style="font-size:0px;padding:10px 25px;padding-top:3px;padding-right:5px;padding-bottom:3px;padding-left:5px;word-break:break-word;">\r\n                  \r\n      <div style="font-family:Arial;font-size:16px;font-weight:400;line-height:150%;text-align:left;color:#333333;"><div><div>⚡️&nbsp;<span><strong>New Performance Optimization Features:</strong></span> We've added performance optimization features to tackle performance challenges:</div><ul><li><span><strong>Optimize In-project Tab Rendering:</strong></span> When enabled, only the form state of tabs (such as endpoints, test scenarios, etc.) will be cached during tab switching in a project, without rendering the HTML DOM tree. This can help reduce lag.&nbsp;</li></ul><ul><li><span><strong>GPU Hardware Acceleration:</strong></span> This feature is enabled by default for smoother rendering. If you notice flickering or incomplete UI elements, you can turn it off to improve stability.</li></ul></div></div>\r\n    \r\n                </td>\r\n              </tr>\r\n            \r\n              <tr>\r\n                <td align="left" style="font-size:0px;padding:10px 25px;padding-top:3px;padding-right:5px;padding-bottom:3px;padding-left:5px;word-break:break-word;">\r\n                  \r\n      <div style="font-family:Arial;font-size:16px;font-weight:400;line-height:150%;text-align:left;color:#333333;"><div>🧩&nbsp;<span><strong>Enhanced Variable Handling:</strong></span> Support for extracting&nbsp;<span style="background-color:#e5e6eb">null</span> as a variable value, providing more flexibility in complex testing scenarios and data manipulation workflows.</div></div>\r\n    \r\n                </td>\r\n              </tr>\r\n            \r\n              <tr>\r\n                <td align="left" style="font-size:0px;padding:10px 25px;padding-top:3px;padding-right:5px;padding-bottom:3px;padding-left:5px;word-break:break-word;">\r\n                  \r\n      <div style="font-family:Arial;font-size:16px;font-weight:400;line-height:150%;text-align:left;color:#333333;"><div>🛡️&nbsp;<span><strong>Streamlined Permission Management:</strong></span> Once a required permission is added, it's automatically assigned to all custom roles, reducing administrative overhead and ensuring consistent access controls.</div></div>\r\n    \r\n                </td>\r\n              </tr>\r\n            \r\n              <tr>\r\n                <td align="left" style="font-size:0px;padding:10px 25px;padding-top:3px;padding-right:5px;padding-bottom:3px;padding-left:5px;word-break:break-word;">\r\n                  \r\n      <div style="font-family:Arial;font-size:16px;font-weight:400;line-height:150%;text-align:left;color:#333333;"><div>&nbsp;</div></div>\r\n    \r\n                </td>\r\n              </tr>\r\n            \r\n              <tr>\r\n                <td align="center" style="font-size:0px;padding:10px 25px;padding-top:3px;padding-right:5px;padding-bottom:3px;padding-left:5px;word-break:break-word;">\r\n                  \r\n      <div style="font-family:Arial;font-size:24px;font-weight:400;line-height:150%;text-align:center;color:#333333;"><div><span><strong>✨ Recommended Readings</strong></span></div></div>\r\n    \r\n                </td>\r\n              </tr>\r\n            \r\n              <tr>\r\n                <td align="left" style="font-size:0px;padding:10px 25px;padding-top:3px;padding-right:5px;padding-bottom:3px;padding-left:5px;word-break:break-word;">\r\n                  \r\n      <div style="font-family:Arial;font-size:16px;font-weight:400;line-height:150%;text-align:left;color:#333333;">Want to maximize your Apidog experience? Check out&nbsp;<span style="color:#1967ff"><a href="https://jff6wzsr.r.us-east-1.awstrack.me/L0/https:%2F%2Fapidog.canny.io%2Fchangelog/15/0100019a2b495a49-82e95d20-5c5a-42c8-9498-e67d45bcf3fe-000000/N6X-2z2VKykGjyXp4O2WnVC19Lc=450" target="_blank"><span><a href="https://jff6wzsr.r.us-east-1.awstrack.me/L0/https:%2F%2Fapidog.com%2Fblog%2F/1/0100019a2b495a49-82e95d20-5c5a-42c8-9498-e67d45bcf3fe-000000/rhUscivYrevhaVab23iEhJ_462k=450" target="_blank">these essential guides</a></span></a></span><span style="color:#1967ff"><a href="https://jff6wzsr.r.us-east-1.awstrack.me/L0/https:%2F%2Fapidog.canny.io%2Fchangelog/16/0100019a2b495a49-82e95d20-5c5a-42c8-9498-e67d45bcf3fe-000000/iQhYj_knX